#creacio de grups

New-ADGroup -Name grup1  `            -GroupScope DomainLocal#Crearlo dins de una UONew-ADGroup -Name grup2  `            -GroupScope 0 `            -Path "OU=unitat1,DC=jtoribio,DC=cat"#Crear un grupo con una descripcionNew-ADGroup -Name grup3  `            -GroupScope 1 `            -Description "Grup numero 3"#Unir usuarios a un grupoAdd-ADGroupMember -Identity grup3 `                  -Members user10,user11#afegir grups a un determinat usuariAdd-ADPrincipalGroupMembership -Identity user10 `                               -MemberOf grup2# quitar de un grup una serie de usuarisRemove-ADGroupMember -Identity grup2 `                     -Members user10 ` #si pones , se pueden quitar mas de un usuario a la vez                     -Confirm:$false  #false en confirm significa que si quieres hacerlo sin confirmacion#Quitar de un usuario una serie de gruposRemove-ADPrincipalGroupMembership -Identity user10 `                                  -MemberOf grup2 ` #si pones , se pueden quitar mas de un grupo a la vez                                  -Confirm:$false#elmininar un grupRemove-ADGroup -Identity grup2 `               -Confirm:$false#HAY QUE HACER LAS DOS SIGUIENTES JUNTAS !! -------------------------------------------------#Renombrar un grup (Nomes el nom del objecte falta cambiar la propietat del nom del grup)Rename-ADObject -Identity "CN=grup2,OU=unitat1,DC=jtoribio,DC=cat" `                -NewName grup4 `                -Confirm:$false#Renombrar la propietat del nom del grupSet-ADGroup -Identity grup2 `            -SamAccountName grup4#--------------------------------------------------------------------------------------------#Mostrar per pantalla les propietats mes important de un grupGet-ADGroup -Identity grup4#Mostrar per pantalla el objectes que perteañen al grup 2 Get-ADGroupMember -Identity grup2#Mostrar per pantalla les grups que perteañen al usuari mindundiGet-ADPrincipalGroupMembership -Identity mindundi                     